        "name": "typography.tsx",
        "content": "\"use client\";\nimport React from \"react\";\nimport { cva } from \"class-variance-authority\";\nimport { cn } from \"@/lib/utils\";\n\nconst headingVariants = cva(\n  \"font-bold tracking-tight text-foreground\",\n  {\n    variants: {\n      variant: {\n        h1: \"scroll-m-20 text-4xl font-extrabold lg:text-5xl\",\n        h2: \"scroll-m-20 border-b pb-2 text-3xl font-semibold first:mt-0\",\n        h3: \"scroll-m-20 text-2xl font-semibold\",\n        h4: \"scroll-m-20 text-xl font-semibold\",\n        h5: \"text-lg font-semibold\",\n        h6: \"text-base font-semibold\",\n      },\n    },\n    defaultVariants: {\n      variant: \"h1\",\n    },\n  }\n);\n\nconst textVariants = cva(\n  \"text-foreground\",\n  {\n    variants: {\n      variant: {\n        default: \"leading-7 [&:not(:first-child)]:mt-6\",\n        lead: \"text-xl text-muted-foreground\",\n        large: \"text-lg font-semibold\",\n        small: \"text-sm font-medium leading-none\",\n        muted: \"text-sm text-muted-foreground\",\n        blockquote: \"mt-6 border-l-2 pl-6 italic\",\n      },\n    },\n    defaultVariants: {\n      variant: \"default\",\n    },\n  }\n);\n\nexport interface HeadingProps extends React.HTMLAttributes<HTMLHeadingElement> {\n  variant?: \"h1\" | \"h2\" | \"h3\" | \"h4\" | \"h5\" | \"h6\";\n  as?: any;\n}\n\nexport const Heading: React.FC<HeadingProps> = ({ className, variant, as: Tag = \"h1\", ...props }) => {\n  return (\n    <Tag\n      className={cn(headingVariants({ variant, className }))}\n      {...props}\n    />\n  );\n};\n\nexport interface TextProps extends React.HTMLAttributes<HTMLParagraphElement> {\n  variant?: \"default\" | \"lead\" | \"large\" | \"small\" | \"muted\" | \"blockquote\";\n  as?: any;\n}\n\nexport const Text: React.FC<TextProps> = ({ className, variant, as: Tag = \"p\", ...props }) => {\n  return (\n    <Tag\n      className={cn(textVariants({ variant, className }))}\n      {...props}\n    />\n  );\n};\n\nexport const Label: React.FC<React.LabelHTMLAttributes<HTMLLabelElement>> = ({ className, ...props }) => (\n  <label\n    className={cn(\n      \"text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70\",\n      className\n    )}\n    {...props}\n  />\n);\n\nexport const Code: React.FC<React.HTMLAttributes<HTMLElement>> = ({ className, ...props }) => (\n  <code\n    className={cn(\n      \"relative rounded bg-muted px-[0.3rem] py-[0.2rem] font-mono text-sm font-semibold\",\n      className\n    )}\n    {...props}\n  />\n);",
